1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Edge case: empty quote =====
6	  it.todo("quote with empty item list returns premium 5 G (only processing fee)");
7	
8	  // ===== Base premiums per item type =====
9	  it.todo("quote for a single plain sword (newcomer, first insurance) returns premium 115 G (100 base + 10 first + 5 fee)");
10	  it.todo("quote for a single plain amulet (newcomer, first insurance) returns premium 71 G (60 base + 6 first + 5 fee)");
11	  it.todo("quote for a single plain staff (newcomer, first insurance) returns premium 93 G (80 base + 8 first + 5 fee)");
12	  it.todo("quote for a single plain potion (newcomer, first insurance) returns premium 49 G (40 base + 4 first + 5 fee)");
13	  it.todo("quote for a single component (newcomer, first insurance) returns premium 33 G (25 base + 2.5 first → 27.5 + 5 fee = 32.5 → round up to 33 G)");
14	
15	  // ===== Block-of-3 alike components (base premium examples) =====
16	  it.todo("quote base premium for 2 runes is 50 G (no block)");
17	  it.todo("quote base premium for 3 runes is 60 G (block applies)");
18	  it.todo("quote base premium for 4 runes is 100 G (no block — block requires exactly 3)");
19	  it.todo("quote base premium for 7 runes is 175 G (no block: 7×25)");
20	
21	  // ===== Alike components clarification =====
22	  it.todo("quote base premium for 2 runes + 1 moonstone is 75 G (no block: different types)");
23	  it.todo("quote base premium for 3 runes + 3 moonstones is 120 G (two separate blocks)");
24	
25	  // ===== Item-specific modifiers in isolation =====
26	  it.todo("cursed sword item modifier adds 50% surcharge to that item's base (100 G → 150 G item subtotal)");
27	  it.todo("high-enchantment sword (enchantment 5) adds 30% surcharge to that item's base");
28	  it.todo("sword with enchantment 4 does NOT get high-enchantment surcharge");
29	  it.todo("cursed AND high-enchantment sword (enchantment 5) gets both surcharges");
30	
31	  // ===== Policy-wide modifiers in isolation =====
32	  it.todo("loyalty discount applies for customer with exactly 2 years (20% off policy base)");
33	  it.todo("loyalty discount does NOT apply for customer with 1 year");
34	  it.todo("first insurance surcharge adds 10% per item (each item in the quote is treated as first insurance)");
35	  it.todo("follow-up contract discount (-15%) applies to second quote in scenario");
36	
37	  // ===== Modifier scope (multi-item policy) =====
38	  it.todo("policy with cursed sword (100 G) + plain amulet (60 G) has policy base 160 G; curse adds 50 G (50% of sword only) → 210 G before policy modifiers and fee");
39	
40	  // ===== Integration: Newcomer with a cursed sword =====
41	  it.todo("newcomer (0 years) with cursed sword (steel, enchantment 3) gets premium 165 G (100 base + 50 curse + 10 first = 160 + 5 fee)");
42	
43	  // ===== Integration: Long-standing customer's second contract =====
44	  it.todo("3-year customer's second quote of cursed sword (steel, enchantment 7) gets premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first − 15 follow-up = 155 + 5 fee)");
45	
46	  // ===== Rounding rules =====
47	  it.todo("premium calculation yielding 197.5 G is rounded UP to 198 G (in MHPCO's favor)");
48	  it.todo("intermediate amounts are kept as fractions; only the final premium is rounded");
49	
50	  // ===== Claim: standard reimbursement =====
51	  it.todo("claim on regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 − 100 deductible)");
52	  it.todo("claim on a rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100 deductible; no special clause for components)");
53	
54	  // ===== Claim: enchantment threshold and dragon material =====
55	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins: 500 − 100)");
56	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement: 800 − 100)");
57	  it.todo("claim on steel sword, enchantment 9, damage 1000 G → payout 400 G (50% rule: 500 − 100)");
58	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench applies: 500 − 100)");
59	
60	  // ===== Claim: deductible per damage event =====
61	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → total payout 600 G (100 G deductible per damaged item: 400 + 200)");
62	
63	  // ===== Claim: multiple items of same type =====
64	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
65	  it.todo("dragon attack damages both of two insured swords → each damage entry gets its own deductible");
66	  it.todo("claim references more swords damaged than insured (2 sword damages, 1 sword insured) → error / rejection");
67	
68	  // ===== Claim: cap and insurance sum =====
69	  it.todo("policy with sword + amulet has insurance sum 1600 G and cap 3200 G");
70	  it.todo("policy with cursed sword has cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
71	  it.todo("policy with sword + 3 runes (block) has insurance sum 1750 G (block discount affects premium only, not insurance sum)");
72	
73	  // ===== Claim: cap exhaustion across successive claims =====
74	  it.todo("sword insured (cap 2000 G), first claim of 1500 G → payout 1400 G, remainingCap 600 G");
75	  it.todo("after first claim used 1400 G, second claim of 1500 G → payout 600 G (reduced to remaining cap), remainingCap 0 G");
76	
77	  // ===== Claim: payout rounding =====
78	  it.todo("payout calculation yielding 350.5 G is rounded DOWN to 350 G (in MHPCO's favor)");
79	
80	  // ===== Edge cases / errors =====
81	  it.todo("quote with unknown item type (e.g. broomstick) → error");
82	  it.todo("claim references damage to item not in policy (e.g. amulet damaged when only sword insured) → error");
83	  it.todo("claim references damage to unknown item type → error");
84	  it.todo("claim with negative damage amount → error");
85	
86	  // ===== CLI =====
87	  it.todo("CLI reads JSON scenario from stdin and writes JSON results to stdout (schema-example scenario)");
88	  it.todo("CLI exits with non-zero status on unknown item type in quote; writes error to stderr; no results on stdout");
89	  it.todo("CLI exits with non-zero status when claim references item not in policy; writes error to stderr");
90	  it.todo("CLI exits with non-zero status when claim contains negative damage amount; writes error to stderr");
91	  it.todo("CLI exits with non-zero status when claim has more damages of a type than policy covers");
92	});
